(() => {
  const utils = window.IKSASS || {};
  const escapeHtml = utils.escapeHtml || ((value) => String(value || ''));
  const toRootUrl = utils.toRootUrl || ((value) => String(value || ''));

  const host = document.querySelector('[data-bukan-pilihan]');
  if (!host) return;

  const prefersReduced = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const fallbackList = [
    { src: '/assets/img/sidebar/bukan-pilihan-1.jpg', alt: 'Bukan Pilihan' },
    { src: '/assets/img/sidebar/bukan-pilihan-2.jpg', alt: 'Bukan Pilihan' },
    { src: '/assets/img/sidebar/bukan-pilihan-3.jpg', alt: 'Bukan Pilihan' },
    { src: '/assets/img/sidebar/bukan-pilihan-4.jpg', alt: 'Bukan Pilihan' },
    { src: '/assets/img/sidebar/bukan-pilihan-5.jpg', alt: 'Bukan Pilihan' },
    { src: '/assets/img/sidebar/bukan-pilihan-6.jpg', alt: 'Salam Perjuangan' },
  ];

  function render(item) {
    const src = escapeHtml(toRootUrl(item?.src || fallbackList[0].src));
    const alt = escapeHtml(item?.alt || 'Bukan Pilihan');
    host.innerHTML = `
      <figure class="bukan-pilihan__media">
        <img class="bukan-pilihan__img" src="${src}" alt="${alt}" loading="lazy" decoding="async" width="900" height="1125">
      </figure>
    `;
  }

  function startRotation(list) {
    if (!Array.isArray(list) || !list.length) return;
    let index = 0;
    render(list[index]);
    if (list.length < 2 || prefersReduced) return;
    window.setInterval(() => {
      index = (index + 1) % list.length;
      host.classList.remove('is-fade');
      void host.offsetWidth;
      host.classList.add('is-fade');
      render(list[index]);
    }, 7000);
  }

  render(fallbackList[0]);

  fetch(toRootUrl('data/bukan-pilihan.json'), { cache: 'no-store' })
    .then((response) => (response.ok ? response.json() : Promise.reject(new Error('bukan-pilihan'))))
    .then((list) => {
      const safeList = Array.isArray(list)
        ? list.filter((item) => item && typeof item === 'object' && String(item.src || '').trim())
        : [];
      startRotation(safeList.length ? safeList : fallbackList);
    })
    .catch(() => {
      startRotation(fallbackList);
    });
})();
